async function loadSettings(){try{const{data}=await sb.from('einstellungen').select('*').eq('user_id',me.id).single();if(data)settings={...settings,...data};}catch(e){}}
async function saveSettings(){const o={user_id:me.id,firma:document.getElementById('s-firma').value,adresse:document.getElementById('s-adr').value,telefon:document.getElementById('s-tel').value,email:document.getElementById('s-em').value,mwst:parseFloat(document.getElementById('s-mwst').value)||19,zahlungsziel:parseInt(document.getElementById('s-ziel').value)||14,iban:document.getElementById('s-iban').value,bank:document.getElementById('s-bank').value,ustid:document.getElementById('s-ustid').value,steuernr:document.getElementById('s-steuernr').value};const{error}=await sb.from('einstellungen').upsert(o,{onConflict:'user_id'});if(error){alert('Fehler: '+error.message);return;}settings={...settings,...o};alert('Gespeichert!');pgEinst();}
async function pgDash(){ld();try{const[r1,r2,r3,r4]=await Promise.all([sb.from('projekte').select('*'),sb.from('kunden').select('*'),sb.from('termine').select('*'),sb.from('rechnungen').select('betrag,status')]);const proj=r1.data||[],ku=r2.data||[],t=r3.data||[],r=r4.data||[];const offen=r.filter(x=>x.status==='offen').reduce((s,x)=>s+(parseFloat(x.betrag)||0),0);const hT=t.filter(x=>x.datum===heute());sC(`<div class="ph"><div><div class="pt">Guten Tag!</div><div class="ps">Übersicht deiner Baustellen</div></div></div><div class="sts"><div class="st" onclick="go('proj')" style="cursor:pointer"><div class="si">🏗️</div><div class="sv">${proj.length}</div><div class="sl">Projekte</div></div><div class="st g" onclick="go('kunden')" style="cursor:pointer"><div class="si">👥</div><div class="sv">${ku.length}</div><div class="sl">Kunden</div></div><div class="st o" onclick="go('termine')" style="cursor:pointer"><div class="si">📅</div><div class="sv">${hT.length}</div><div class="sl">Heute Termine</div></div><div class="st pu" onclick="go('rech')" style="cursor:pointer"><div class="si">💶</div><div class="sv">€${offen.toFixed(0)}</div><div class="sl">Offene Rechnungen</div></div></div><div class="sh">Aktuelle Projekte</div>${!proj.length?'<div class="em"><div class="em-i">🏗️</div><div class="em-t">Noch keine Projekte</div></div>':`<div class="gr">${proj.slice(0,6).map(p=>`<div class="ca" onclick="pgProjDetail('${p.id}')"><div class="ca-t">${p.name||'-'}</div><div class="ca-s">${p.kunde||p.kunde_name||'-'}</div>${p.adresse?`<div style="font-size:11px;color:var(--muted);margin-top:6px">📍 ${p.adresse}</div>`:''}<div class="ca-f"><span class="bd ${p.status==='Abgeschlossen'?'bd-g':p.status==='Pausiert'?'bd-o':'bd-b'}">${p.status||'Aktiv'}</span></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">Fehler: ${e.message}</div></div>`);}}
async function pgKunden(){ld();try{const{data}=await sb.from('kunden').select('*').order('created_at',{ascending:false});sC(`<div class="ph"><div><div class="pt">Kunden</div><div class="ps">${(data||[]).length} Kunde(n)</div></div><button class="bp" onclick="mKunde()">+ Neuer Kunde</button></div>${!(data&&data.length)?'<div class="em"><div class="em-i">👥</div><div class="em-t">Noch keine Kunden</div></div>':`<div class="gr">${data.map(k=>`<div class="ca" onclick='mKunde(${JSON.stringify(k).replace(/'/g,"&#39;")})'><div style="display:flex;align-items:center;gap:10px"><div style="width:40px;height:40px;background:var(--pl);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;font-weight:800;color:var(--p)">${(k.name||'?')[0].toUpperCase()}</div><div><div class="ca-t">${k.name||'-'}</div><div class="ca-s">${k.telefon||k.email||'-'}</div></div></div>${k.adresse?`<div style="font-size:11px;color:var(--muted);margin-top:8px">📍 ${k.adresse}</div>`:''}</div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mKunde(k={}){oM(`<div class="mt">${k.id?'Kunde bearbeiten':'Neuer Kunde'}</div><div class="fg"><label>NAME *</label><input id="f-n" value="${k.name||''}" placeholder="Frank Müller"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="f-tel" value="${k.telefon||''}" placeholder="+49 176 ..."></div><div class="fg"><label>E-MAIL</label><input id="f-em" value="${k.email||''}" placeholder="info@..."></div></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${k.adresse||''}" placeholder="Musterstr. 1, Berlin"></div><div class="fg"><label>NOTIZ</label><textarea id="f-not" rows="2">${k.notiz||''}</textarea></div><div class="ma">${k.id?`<button class="bc" style="background:var(--red);color:#fff" onclick="delKunde('${k.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveKunde('${k.id||''}')">Speichern</button></div>`);}
async function saveKunde(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Bitte Name eingeben!');return;}const o={name:n,telefon:document.getElementById('f-tel').value,email:document.getElementById('f-em').value,adresse:document.getElementById('f-adr').value,notiz:document.getElementById('f-not').value,user_id:me.id};const{error}=id?await sb.from('kunden').update(o).eq('id',id):await sb.from('kunden').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgKunden();}
async function delKunde(id){if(!confirm('Kunde wirklich löschen?'))return;await sb.from('kunden').delete().eq('id',id);cM();pgKunden();}
async function pgProj(){ld();try{const{data}=await sb.from('projekte').select('*').order('created_at',{ascending:false});sC(`<div class="ph"><div><div class="pt">Projekte</div><div class="ps">${(data||[]).length} Projekt(e)</div></div><button class="bp" onclick="mProj()">+ Neues Projekt</button></div>${!(data&&data.length)?'<div class="em"><div class="em-i">🏗️</div><div class="em-t">Noch keine Projekte</div></div>':`<div class="gr">${data.map(p=>`<div class="ca" onclick="pgProjDetail('${p.id}')"><div class="ca-t">${p.name||'-'}</div><div class="ca-s">${p.kunde||p.kunde_name||'-'}</div>${p.adresse?`<div style="font-size:11px;color:var(--muted);margin-top:5px">📍 ${p.adresse}</div>`:''}<div class="ca-f"><span class="bd ${p.status==='Abgeschlossen'?'bd-g':p.status==='Pausiert'?'bd-o':'bd-b'}">${p.status||'Aktiv'}</span></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
async function mProj(){const{data:ku}=await sb.from('kunden').select('id,name');oM(`<div class="mt">Neues Projekt</div><div class="fg"><label>PROJEKTNAME *</label><input id="f-n" placeholder="z.B. Baustelle Berlin"></div><div class="fg"><label>KUNDE</label><select id="f-ku"><option value="">- Kein Kunde -</option>${(ku||[]).map(k=>`<option value="${k.id}" data-n="${k.name}">${k.name}</option>`).join('')}</select></div><div class="fg"><label>ADRESSE</label><input id="f-adr" placeholder="Musterstraße 1, Berlin"></div><div class="fg"><label>STATUS</label><select id="f-st"><option value="Aktiv">Aktiv</option><option value="Pausiert">Pausiert</option><option value="Abgeschlossen">Abgeschlossen</option></select></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-desc" rows="3"></textarea></div><div class="fr"><div class="fg"><label>START</label><input id="f-start" type="date" value="${heute()}"></div><div class="fg"><label>ENDE</label><input id="f-end" type="date"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveProj()">Speichern</button></div>`);}
async function saveProj(){const n=document.getElementById('f-n').value.trim();if(!n){alert('Projektname fehlt!');return;}const s=document.getElementById('f-ku');const ki=s.value||null,kn=ki?s.options[s.selectedIndex].dataset.n:'';const{error}=await sb.from('projekte').insert({name:n,kunden_id:ki,kunde_name:kn,kunde:kn,adresse:document.getElementById('f-adr').value,beschreibung:document.getElementById('f-desc').value,status:document.getElementById('f-st').value,datum_start:document.getElementById('f-start').value||null,datum_end:document.getElementById('f-end').value||null,autor_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgProj();}
async function delProj(id){if(!confirm('Projekt wirklich löschen?'))return;await sb.from('projekte').delete().eq('id',id);pgProj();}
async function pgProjDetail(id){ld();const[{data:p},{data:bt},{data:mat},{data:std},{data:ang},{data:abn}]=await Promise.all([sb.from('projekte').select('*').eq('id',id).single(),sb.from('bautagebuch').select('*').eq('projekt_id',id).order('datum',{ascending:false}),sb.from('material').select('*').eq('projekt_id',id),sb.from('stunden').select('*').eq('projekt_id',id),sb.from('angebote').select('*').eq('projekt_id',id),sb.from('abnahmen').select('*').eq('projekt_id',id).order('datum',{ascending:false})]);
const kostenStunden=(std||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);
const kostenMaterial=(mat||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);
const gesamtStunden=(std||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);
const gesamtKosten=kostenStunden+kostenMaterial;
const mapQ=encodeURIComponent(p?.adresse||'Berlin');
sC(`<button class="bk" onclick="pgProj()">← Zurück</button><div class="ph"><div><div class="pt">${p?.name||'Projekt'}</div><div class="ps">${p?.kunde||p?.kunde_name||''} ${p?.adresse?'· '+p.adresse:''}</div></div><button class="bp" onclick="mProjEdit('${id}')" style="background:var(--pl);color:var(--pd)">Bearbeiten</button></div>
<div style="background:#fff;border-radius:14px;padding:16px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,0.08)">
<div style="font-size:11px;font-weight:700;color:var(--muted);letter-spacing:1px;margin-bottom:12px">KOSTENÜBERSICHT</div>
<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text)">⏱️ Stunden (${gesamtStunden.toFixed(1)}h)</span><span style="font-weight:700">€${kostenStunden.toFixed(2)}</span></div>
<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)"><span style="color:var(--text)">🧱 Material (${(mat||[]).length} Pos.)</span><span style="font-weight:700">€${kostenMaterial.toFixed(2)}</span></div>
<div style="display:flex;justify-content:space-between;padding:10px 0;margin-top:4px"><span style="font-weight:800;font-size:15px">Gesamt</span><span style="font-weight:800;font-size:15px;color:var(--p)">€${gesamtKosten.toFixed(2)}</span></div>
<div style="display:flex;gap:8px;margin-top:8px">
<button class="bp" style="flex:1;padding:10px" onclick="angAusKosten('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}',${kostenStunden},${kostenMaterial},${JSON.stringify(std||[]).replace(/'/g,'&#39;').replace(/"/g,'&quot;')},${JSON.stringify(mat||[]).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})">→ Angebot erstellen</button>
<button class="bp" style="flex:1;padding:10px;background:#10b981" onclick="rechAusKosten('${id}','${p?.kunde||p?.kunde_name||''}',${gesamtKosten})">→ Rechnung erstellen</button>
</div></div>
${p?.adresse?`<div class="map-wrap"><iframe src="https://maps.google.com/maps?q=${mapQ}&output=embed&z=15" allowfullscreen></iframe></div>`:''}<div class="sh">Bautagebuch (${(bt||[]).length})</div><div class="tc"><div class="th"><span class="th-t">Einträge</span><button class="bp" style="padding:7px 12px;font-size:12px" onclick="mBt('${id}')">+ Eintrag</button></div><table><thead><tr><th>Datum</th><th>Beschreibung</th><th>Zeit</th><th></th></tr></thead><tbody>${!(bt&&bt.length)?'<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted)">Keine Einträge</td></tr>':bt.map(e=>`<tr><td>${fmtDatum(e.datum)}</td><td>${e.beschreibung||'-'}</td><td>${e.zeit_von||'-'} - ${e.zeit_bis||'-'}</td><td style="white-space:nowrap"><button onclick="loadAndExportBt('${e.id}','${p?.name||''}')" style="background:none;border:none;cursor:pointer;font-size:16px">📄</button><button onclick="delBt('${e.id}','${id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Abnahmen (${(abn||[]).length})</div><div class="tc"><div class="th"><span class="th-t">Abnahmen</span><button class="bp" style="padding:7px 12px;font-size:12px;background:#10b981" onclick="mAbnahme('${id}','${p?.name||''}','${p?.kunde||p?.kunde_name||''}')">+ Abnahme</button></div><table><thead><tr><th>Datum</th><th>Auftraggeber</th><th>Mängel</th><th></th></tr></thead><tbody>${!(abn&&abn.length)?'<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted)">Keine Abnahmen</td></tr>':abn.map(a=>`<tr><td>${fmtDatum(a.datum)}</td><td>${a.auftraggeber||'-'}</td><td>${a.maengel?'Ja':'Keine'}</td><td><button onclick="exportAbnahmePDF(${JSON.stringify(a).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})" style="background:none;border:none;cursor:pointer;font-size:16px">📄</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Angebote (${(ang||[]).length})</div><div class="tc"><div class="th"><span class="th-t">Angebote</span><button class="bp" style="padding:7px 12px;font-size:12px" onclick="mAng('${id}','${p?.kunde||p?.kunde_name||''}')">+ Angebot</button></div><table><thead><tr><th>Nr.</th><th>Titel</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(ang&&ang.length)?'<tr><td colspan="5" style="text-align:center;padding:20px;color:var(--muted)">Keine Angebote</td></tr>':ang.map(a=>`<tr><td style="font-family:monospace;font-size:11px">${a.nummer||'-'}</td><td>${a.titel||'-'}</td><td><b>€${parseFloat(a.gesamt||0).toFixed(2)}</b></td><td><span class="bd ${a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o'}">${a.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="angToRech('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;font-size:16px" title="Zu Rechnung">🧾</button><button onclick="delAng('${a.id}','${id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Material (${(mat||[]).length})</div><div class="tc"><div class="th"><span class="th-t">Material</span><button class="bp" style="padding:7px 12px;font-size:12px" onclick="mMat2('${id}')">+ Material</button></div><table><thead><tr><th>Material</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(mat&&mat.length)?'<tr><td colspan="4" style="text-align:center;padding:20px;color:var(--muted)">Kein Material</td></tr>':mat.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><b>${m.name||'-'}</b></td><td>${m.menge||'-'}</td><td>${m.preis?'€'+parseFloat(m.preis).toFixed(2):'-'}</td><td><button onclick="event.stopPropagation();delMat('${m.id}','${id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div><div class="sh">Stunden (${(std||[]).length})</div><div class="tc"><div class="th"><span class="th-t">Stunden</span><button class="bp" style="padding:7px 12px;font-size:12px" onclick="mStd2('${id}')">+ Stunden</button></div><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(std&&std.length)?'<tr><td colspan="5" style="text-align:center;padding:20px;color:var(--muted)">Keine Stunden</td></tr>':std.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td><b>${s.stunden||0}h</b></td><td>${satz>0?'€'+kosten.toFixed(2):'-'}</td><td><button onclick="delStd('${s.id}','${id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`;}).join('')}</tbody></table></div><div class="sh">Fotos</div><div class="photo-up" onclick="document.getElementById('fi').click()"><input type="file" id="fi" accept="image/*" multiple style="display:none" onchange="upFotos('${id}')"><div style="font-size:24px;margin-bottom:6px">📷</div><div style="font-weight:700;font-size:13px">Fotos hinzufügen</div></div><div id="fp" class="photo-prev"></div>`);}

function angAusKosten(pid,pname,kunde,kostenStd,kostenMat,std,mat){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const pos=[];if(kostenStd>0)pos.push({name:'Lohnkosten',preis:kostenStd});if(kostenMat>0)pos.push({name:'Materialkosten',preis:kostenMat});const gesamt=kostenStd+kostenMat;oM(`<div class="mt">Angebot aus Projektkosten</div><div style="background:var(--pl);border-radius:10px;padding:12px;margin-bottom:14px"><div style="font-size:13px;font-weight:700">${pname||'Projekt'}</div><div style="font-size:12px;color:var(--muted);margin-top:4px">Lohnkosten: €${kostenStd.toFixed(2)} · Material: €${kostenMat.toFixed(2)}</div></div><div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" value="Arbeiten ${pname||''}" placeholder="Angebotstitel"></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kunde||''}" placeholder="Kundenname"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap">${pos.map(p=>`<div class="offer-row"><input value="${p.name}" class="pos-name"><input value="${p.preis.toFixed(2)}" type="number" class="pos-price price-inp" oninput="calcTotal()"></div>`).join('')}</div><button type="button" onclick="addPos()" style="margin-top:6px;padding:6px 12px;background:var(--pl);color:var(--pd);border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit">+ Position</button><div class="offer-total">Gesamt: €<span id="tot">${gesamt.toFixed(2)}</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="angenommen">Angenommen</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAngMitPid('${pid}')">Speichern</button></div>`);}

async function saveAngMitPid(pid){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:pid,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value,user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}

async function rechAusKosten(pid,kunde,betrag){if(!confirm('Rechnung über €'+betrag.toFixed(2)+' erstellen?'))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid,kunde:kunde,datum:heute(),betrag:betrag,status:'offen'});if(error){alert('Fehler: '+error.message);return;}if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}

async function angToRech(aid,pid){const{data:a}=await sb.from('angebote').select('*').eq('id',aid).single();if(!a)return;if(!confirm('Angebot in Rechnung umwandeln?'))return;const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);const{error}=await sb.from('rechnungen').insert({rechnungsnummer:nr,projekt_id:pid,kunde:a.kunde,datum:heute(),betrag:a.gesamt,status:'offen'});if(error){alert('Fehler: '+error.message);return;}await sb.from('angebote').update({status:'angenommen'}).eq('id',aid);if(confirm('Rechnung erstellt! Jetzt zur Rechnung?'))go('rech');else pgProjDetail(pid);}

async function mProjEdit(id){const{data:p}=await sb.from('projekte').select('*').eq('id',id).single();const{data:ku}=await sb.from('kunden').select('id,name');oM(`<div class="mt">Projekt bearbeiten</div><div class="fg"><label>PROJEKTNAME *</label><input id="f-n" value="${p.name||''}"></div><div class="fg"><label>KUNDE</label><select id="f-ku"><option value="">- Kein Kunde -</option>${(ku||[]).map(k=>`<option value="${k.id}" data-n="${k.name}"${k.id===p.kunden_id?' selected':''}>${k.name}</option>`).join('')}</select></div><div class="fg"><label>ADRESSE</label><input id="f-adr" value="${p.adresse||''}"></div><div class="fg"><label>STATUS</label><select id="f-st"><option value="Aktiv"${p.status==='Aktiv'?' selected':''}>Aktiv</option><option value="Pausiert"${p.status==='Pausiert'?' selected':''}>Pausiert</option><option value="Abgeschlossen"${p.status==='Abgeschlossen'?' selected':''}>Abgeschlossen</option></select></div><div class="fg"><label>BESCHREIBUNG</label><textarea id="f-desc" rows="3">${p.beschreibung||''}</textarea></div><div class="fr"><div class="fg"><label>START</label><input id="f-start" type="date" value="${p.datum_start||''}"></div><div class="fg"><label>ENDE</label><input id="f-end" type="date" value="${p.datum_end||''}"></div></div><div class="ma"><button class="bc" style="background:var(--red);color:#fff" onclick="delProj('${id}')">Löschen</button><button class="bs" onclick="saveProjEdit('${id}')">Speichern</button></div>`);}
async function saveProjEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Projektname fehlt!');return;}const s=document.getElementById('f-ku');const ki=s.value||null,kn=ki?s.options[s.selectedIndex].dataset.n:'';const{error}=await sb.from('projekte').update({name:n,kunden_id:ki,kunde_name:kn,kunde:kn,adresse:document.getElementById('f-adr').value,beschreibung:document.getElementById('f-desc').value,status:document.getElementById('f-st').value,datum_start:document.getElementById('f-start').value||null,datum_end:document.getElementById('f-end').value||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(id);}
async function upFotos(pid){const files=document.getElementById('fi').files;const prev=document.getElementById('fp');for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);await sb.storage.from('fotos').upload(`${pid}/${Date.now()}_${f.name}`,f).catch(()=>{});}}
async function delBt(id,pid){if(!confirm('Eintrag löschen?'))return;await sb.from('bautagebuch').delete().eq('id',id);pgProjDetail(pid);}
async function delMat(id,pid){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgProjDetail(pid);}
async function delStd(id,pid){if(!confirm('Stunden löschen?'))return;await sb.from('stunden').delete().eq('id',id);pgProjDetail(pid);}
async function delAng(id,pid){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgProjDetail(pid);}
function mMatEdit(id,name,menge,preis){oM(`<div class="mt">Material bearbeiten</div><div class="fg"><label>MATERIALNAME *</label><input id="f-n" value="${name}"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" value="${menge}"></div><div class="fg"><label>PREIS (€)</label><input id="f-pr" type="number" step="0.01" value="${preis}"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMatEdit('${id}')">Speichern</button></div>`);}
async function saveMatEdit(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').update({name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null}).eq('id',id);if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(id);}
async function pgTermine(){ld();try{const h=new Date();const[{data},{data:proj}]=await Promise.all([sb.from('termine').select('*').order('datum'),sb.from('projekte').select('id,name')]);const yr=h.getFullYear(),mo=h.getMonth();const firstDay=new Date(yr,mo,1).getDay();const dim=new Date(yr,mo+1,0).getDate();const monate=['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];let cc='';const pad=n=>String(n).padStart(2,'0');for(let i=0;i<(firstDay===0?6:firstDay-1);i++)cc+=`<div class="cal-day" style="background:#fafafa"></div>`;for(let d=1;d<=dim;d++){const ds=`${yr}-${pad(mo+1)}-${pad(d)}`;const de=(data||[]).filter(t=>t.datum===ds);const it=ds===heute();cc+=`<div class="cal-day${it?' today':''}" onclick='mTermin("${ds}",${JSON.stringify(proj||[]).replace(/"/g,"&quot;")})'><div class="cal-dn${it?' cur':''}">${d}</div>${de.slice(0,2).map(e=>`<div class="cal-ev">${e.titel||'Termin'}</div>`).join('')}</div>`;}const up=(data||[]).filter(t=>t.datum>=heute()).slice(0,10);sC(`<div class="ph"><div><div class="pt">Termine</div><div class="ps">${(data||[]).length} Termin(e)</div></div><button class="bp" onclick='mTermin("",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neuer Termin</button></div><div class="cal"><div class="cal-head"><div style="font-size:15px;font-weight:700">${monate[mo]} ${yr}</div></div><div class="cal-grid"><div class="cal-day-h">Mo</div><div class="cal-day-h">Di</div><div class="cal-day-h">Mi</div><div class="cal-day-h">Do</div><div class="cal-day-h">Fr</div><div class="cal-day-h">Sa</div><div class="cal-day-h">So</div>${cc}</div></div><div class="sh">Kommende Termine</div><div class="tc"><table><thead><tr><th>Datum</th><th>Zeit</th><th>Titel</th><th>Status</th><th></th></tr></thead><tbody>${!up.length?'<tr><td colspan="5" style="text-align:center;padding:20px;color:var(--muted)">Keine Termine</td></tr>':up.map(t=>`<tr onclick="mTerminEdit('${t.id}','${t.titel||''}','${t.datum||''}','${t.uhrzeit||''}','${t.status||''}','${t.projekt_id||''}',${JSON.stringify(proj||[]).replace(/'/g,'&#39;').replace(/"/g,'&quot;')})" style="cursor:pointer"><td>${fmtDatum(t.datum)}</td><td>${t.uhrzeit||'-'}</td><td><b>${t.titel||'-'}</b></td><td><span class="bd ${t.status==='erledigt'?'bd-g':t.status==='abgesagt'?'bd-r':'bd-b'}">${t.status||'geplant'}</span></td><td><button onclick="event.stopPropagation();delTermin('${t.id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mTermin(datum,proj){oM(`<div class="mt">Neuer Termin</div><div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Wartungsarbeiten"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="08:00"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant">Geplant</option><option value="erledigt">Erledigt</option><option value="abgesagt">Abgesagt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveTermin('')">Speichern</button></div>`);}
function mTerminEdit(id,titel,datum,uhrzeit,status,pid,proj){oM(`<div class="mt">Termin bearbeiten</div><div class="fg"><label>TITEL *</label><input id="f-t" value="${titel}"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fr"><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div><div class="fg"><label>UHRZEIT</label><input id="f-u" type="time" value="${uhrzeit||'08:00'}"></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="geplant"${status==='geplant'?' selected':''}>Geplant</option><option value="erledigt"${status==='erledigt'?' selected':''}>Erledigt</option><option value="abgesagt"${status==='abgesagt'?' selected':''}>Abgesagt</option></select></div><div class="ma"><button class="bc" style="background:var(--red);color:#fff" onclick="delTermin('${id}')">Löschen</button><button class="bs" onclick="saveTermin('${id}')">Speichern</button></div>`);}
async function saveTermin(id){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const o={titel:t,projekt_id:document.getElementById('f-p').value||null,datum:document.getElementById('f-d').value,uhrzeit:document.getElementById('f-u').value,status:document.getElementById('f-s').value,user_id:me.id};const{error}=id?await sb.from('termine').update(o).eq('id',id):await sb.from('termine').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgTermine();}
async function delTermin(id){if(!confirm('Termin löschen?'))return;await sb.from('termine').delete().eq('id',id);cM();pgTermine();}
async function pgAngebote(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('angebote').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);sC(`<div class="ph"><div><div class="pt">Angebote</div><div class="ps">${(data||[]).length} Angebot(e)</div></div><button class="bp" onclick='mAng("","",${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Neues Angebot</button></div><div class="tc"><table><thead><tr><th>Nr.</th><th>Datum</th><th>Titel</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Angebote</div></div></td></tr>':data.map(a=>`<tr><td style="font-family:monospace;font-size:11px">${a.nummer||'-'}</td><td>${fmtDatum(a.datum)}</td><td><b>${a.titel||'-'}</b></td><td><b>€${parseFloat(a.gesamt||0).toFixed(2)}</b></td><td><span class="bd ${a.status==='angenommen'?'bd-g':a.status==='abgelehnt'?'bd-r':'bd-o'}">${a.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="angToRech('${a.id}',null)" style="background:none;border:none;cursor:pointer;font-size:16px" title="Zu Rechnung">🧾</button><button onclick="delAngD('${a.id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mAng(pid,kn,proj){const nr='A-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`<div class="mt">Angebot erstellen</div><div class="fr"><div class="fg"><label>ANGEBOTSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>TITEL *</label><input id="f-t" placeholder="z.B. Sanierungsarbeiten"></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE</label><input id="f-ku" value="${kn||''}" placeholder="Kundenname"></div><div class="fg"><label>POSITIONEN</label><div id="pos-wrap"><div class="offer-row"><input placeholder="Leistung" class="pos-name"><input placeholder="Preis €" type="number" class="pos-price price-inp" oninput="calcTotal()"></div></div><button type="button" onclick="addPos()" style="margin-top:6px;padding:6px 12px;background:var(--pl);color:var(--pd);border:none;border-radius:7px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit">+ Position</button><div class="offer-total">Gesamt: €<span id="tot">0.00</span></div></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="angenommen">Angenommen</option><option value="abgelehnt">Abgelehnt</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAng()">Speichern</button></div>`);}
function addPos(){const w=document.getElementById('pos-wrap');const r=document.createElement('div');r.className='offer-row';r.innerHTML='<input placeholder="Leistung" class="pos-name"><input placeholder="Preis €" type="number" class="pos-price price-inp" oninput="calcTotal()">';w.appendChild(r);}
function calcTotal(){let t=0;document.querySelectorAll('.pos-price').forEach(p=>t+=parseFloat(p.value)||0);document.getElementById('tot').textContent=t.toFixed(2);}
async function saveAng(){const t=document.getElementById('f-t').value.trim();if(!t){alert('Titel fehlt!');return;}const ns=document.querySelectorAll('.pos-name'),ps=document.querySelectorAll('.pos-price');const pos=[];let total=0;ns.forEach((n,i)=>{if(n.value.trim()){const pr=parseFloat(ps[i].value)||0;pos.push({name:n.value,preis:pr});total+=pr;}});const{error}=await sb.from('angebote').insert({nummer:document.getElementById('f-nr').value,titel:t,projekt_id:document.getElementById('f-p').value||null,kunde:document.getElementById('f-ku').value,datum:document.getElementById('f-d').value,positionen:JSON.stringify(pos),gesamt:total,status:document.getElementById('f-s').value,user_id:me.id});if(error){alert('Fehler: '+error.message);return;}cM();pgAngebote();}
async function delAngD(id){if(!confirm('Angebot löschen?'))return;await sb.from('angebote').delete().eq('id',id);pgAngebote();}
async function pgMit(){ld();try{const{data}=await sb.from('mitarbeiter').select('*').order('name');sC(`<div class="ph"><div><div class="pt">Mitarbeiter</div><div class="ps">${(data||[]).length} Mitarbeiter</div></div><button class="bp" onclick="mMitarbeiter()">+ Neu</button></div>${!(data&&data.length)?'<div class="em"><div class="em-i">👷</div><div class="em-t">Noch keine Mitarbeiter</div><button class="bp" style="margin-top:16px" onclick="mMitarbeiter()">+ Mitarbeiter anlegen</button></div>':`<div class="gr">${data.map(m=>`<div class="ca" onclick='mMitarbeiter(${JSON.stringify(m).replace(/'/g,"&#39;")})' style="cursor:pointer"><div style="display:flex;align-items:center;gap:12px"><div style="width:44px;height:44px;background:${m.farbe||'var(--pl)'};border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:#fff">${(m.name||'?')[0].toUpperCase()}</div><div style="flex:1"><div class="ca-t">${m.name||'-'}</div><div class="ca-s">${m.rolle||'Mitarbeiter'}${m.stundensatz?' · €'+m.stundensatz+'/h':''}</div>${m.telefon?`<div style="font-size:12px;margin-top:4px">${fmtTel(m.telefon)}</div>`:''}</div></div></div>`).join('')}</div>`}`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mMitarbeiter(m={}){const farben=['#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4','#f97316','#ec4899'];oM(`<div class="mt">${m.id?'Mitarbeiter bearbeiten':'Neuer Mitarbeiter'}</div><div class="fg"><label>NAME *</label><input id="f-n" value="${m.name||''}" placeholder="Max Mustermann"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="f-tel" value="${m.telefon||''}" placeholder="+49 176 ..."></div><div class="fg"><label>ROLLE</label><select id="f-ro"><option value="Mitarbeiter"${m.rolle==='Mitarbeiter'?' selected':''}>Mitarbeiter</option><option value="Bauleiter"${m.rolle==='Bauleiter'?' selected':''}>Bauleiter</option><option value="Azubi"${m.rolle==='Azubi'?' selected':''}>Azubi</option><option value="Subunternehmer"${m.rolle==='Subunternehmer'?' selected':''}>Subunternehmer</option></select></div></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-sh" type="number" step="0.5" value="${m.stundensatz||''}" placeholder="45.00"></div><div class="fg"><label>FARBE</label><div style="display:flex;gap:8px;flex-wrap:wrap">${farben.map(f=>`<div onclick="document.getElementById('f-farbe').value='${f}';document.querySelectorAll('.farb-btn').forEach(b=>b.style.border='2px solid transparent');this.style.border='2px solid #000'" class="farb-btn" style="width:32px;height:32px;border-radius:50%;background:${f};cursor:pointer;border:${(m.farbe||'#3b82f6')===f?'2px solid #000':'2px solid transparent'}"></div>`).join('')}<input type="hidden" id="f-farbe" value="${m.farbe||'#3b82f6'}"></div></div><div class="ma">${m.id?`<button class="bc" style="background:var(--red);color:#fff" onclick="delMitarbeiter('${m.id}')">Löschen</button>`:'<button class="bc" onclick="cM()">Abbrechen</button>'}<button class="bs" onclick="saveMitarbeiter('${m.id||''}')">Speichern</button></div>`);}
async function saveMitarbeiter(id){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const o={name:n,telefon:document.getElementById('f-tel').value,rolle:document.getElementById('f-ro').value,stundensatz:parseFloat(document.getElementById('f-sh').value)||null,farbe:document.getElementById('f-farbe').value};const{error}=id?await sb.from('mitarbeiter').update(o).eq('id',id):await sb.from('mitarbeiter').insert(o);if(error){alert('Fehler: '+error.message);return;}await loadMitarbeiter();cM();pgMit();}
async function delMitarbeiter(id){if(!confirm('Mitarbeiter löschen?'))return;await sb.from('mitarbeiter').delete().eq('id',id);await loadMitarbeiter();cM();pgMit();}
async function pgStd(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('stunden').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);const total=(data||[]).reduce((s,r)=>s+(parseFloat(r.stunden)||0),0);const totalKosten=(data||[]).reduce((s,r)=>{const mit=_mitarbeiter.find(m=>m.name===r.mitarbeiter_name);const satz=r.stundensatz||mit?.stundensatz||0;return s+(parseFloat(r.stunden)||0)*satz;},0);sC(`<div class="ph"><div><div class="pt">Stunden</div><div class="ps">Gesamt: ${total.toFixed(1)}h · €${totalKosten.toFixed(0)}</div></div><button class="bp" onclick='mStdAllg(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Eintragen</button></div><div class="tc"><table><thead><tr><th>Datum</th><th>Mitarbeiter</th><th>Projekt</th><th>Std</th><th>Kosten</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Einträge</div></div></td></tr>':data.map(s=>{const mit=_mitarbeiter.find(m=>m.name===s.mitarbeiter_name);const satz=s.stundensatz||mit?.stundensatz||0;const kosten=(parseFloat(s.stunden)||0)*satz;return`<tr><td>${fmtDatum(s.datum)}</td><td>${s.mitarbeiter_name||'-'}</td><td>${(proj||[]).find(p=>p.id===s.projekt_id)?.name||'-'}</td><td><b>${s.stunden||0}h</b></td><td>${satz>0?'€'+kosten.toFixed(2):'-'}</td><td><button onclick="delStdD('${s.id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`;}).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mStd2(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}">${m.name}${m.stundensatz?' (€'+m.stundensatz+'/h)':''}</option>`).join('');oM(`<div class="mt">Stunden eintragen</div><input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">- Wählen -</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="wird automatisch befüllt"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" min="0.5" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);}
function mStdAllg(proj){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}" data-satz="${m.stundensatz||0}">${m.name}${m.stundensatz?' (€'+m.stundensatz+'/h)':''}</option>`).join('');oM(`<div class="mt">Stunden eintragen</div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">- Kein Projekt -</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MITARBEITER</label><select id="f-n" onchange="updateSatz(this)"><option value="">- Wählen -</option>${mitOpts}</select></div><div class="fg"><label>STUNDENSATZ (€/h)</label><input id="f-satz" type="number" step="0.5" placeholder="wird automatisch befüllt"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div><div class="fg"><label>STUNDEN *</label><input id="f-s" type="number" step="0.5" min="0.5" max="24" placeholder="8"></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveStd()">Speichern</button></div>`);}
function updateSatz(sel){const satz=sel.options[sel.selectedIndex]?.dataset.satz||0;document.getElementById('f-satz').value=satz||'';}
async function saveStd(){const s=document.getElementById('f-s').value;const n=document.getElementById('f-n').value;if(!s){alert('Stunden fehlen!');return;}const satz=parseFloat(document.getElementById('f-satz').value)||0;const{error}=await sb.from('stunden').insert({projekt_id:document.getElementById('f-p').value||null,mitarbeiter_name:n,datum:document.getElementById('f-d').value,stunden:parseFloat(s),stundensatz:satz,kosten:(parseFloat(s)||0)*satz});if(error){alert('Fehler: '+error.message);return;}cM();pgStd();}
async function delStdD(id){if(!confirm('Eintrag löschen?'))return;await sb.from('stunden').delete().eq('id',id);pgStd();}
async function pgMat(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('material').select('*').order('created_at',{ascending:false}),sb.from('projekte').select('id,name')]);const totalWert=(data||[]).reduce((s,r)=>s+(parseFloat(r.preis)||0),0);sC(`<div class="ph"><div><div class="pt">Material</div><div class="ps">${(data||[]).length} Einträge · €${totalWert.toFixed(0)}</div></div><button class="bp" onclick='mMatAllg(${JSON.stringify(proj||[]).replace(/'/g,"&#39;")})'>+ Hinzufügen</button></div><div class="tc"><table><thead><tr><th>Material</th><th>Projekt</th><th>Menge</th><th>Preis</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="5"><div class="em" style="padding:30px"><div class="em-t">Kein Material</div></div></td></tr>':data.map(m=>`<tr onclick="mMatEdit('${m.id}','${m.name||''}','${m.menge||''}','${m.preis||''}')" style="cursor:pointer"><td><b>${m.name||'-'}</b></td><td>${(proj||[]).find(p=>p.id===m.projekt_id)?.name||m.projekt||'-'}</td><td>${m.menge||'-'}</td><td>${m.preis?'€'+parseFloat(m.preis).toFixed(2):'-'}</td><td><button onclick="event.stopPropagation();delMatD('${m.id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mMat2(pid){oM(`<div class="mt">Material hinzufügen</div><input type="hidden" id="f-p" value="${pid}"><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS (€)</label><input id="f-pr" type="number" step="0.01" placeholder="0.00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
function mMatAllg(proj){oM(`<div class="mt">Material hinzufügen</div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>MATERIALNAME *</label><input id="f-n" placeholder="z.B. Zement"></div><div class="fr"><div class="fg"><label>MENGE</label><input id="f-m" placeholder="50 Säcke"></div><div class="fg"><label>PREIS (€)</label><input id="f-pr" type="number" step="0.01" placeholder="0.00"></div></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveMat()">Speichern</button></div>`);}
async function saveMat(){const n=document.getElementById('f-n').value.trim();if(!n){alert('Name fehlt!');return;}const{error}=await sb.from('material').insert({projekt_id:document.getElementById('f-p').value||null,name:n,menge:document.getElementById('f-m').value,preis:parseFloat(document.getElementById('f-pr').value)||null});if(error){alert('Fehler: '+error.message);return;}cM();pgMat();}
async function delMatD(id){if(!confirm('Material löschen?'))return;await sb.from('material').delete().eq('id',id);pgMat();}
async function pgRech(){ld();try{const[{data},{data:proj}]=await Promise.all([sb.from('rechnungen').select('*').order('datum',{ascending:false}),sb.from('projekte').select('id,name')]);const paid=(data||[]).filter(r=>r.status==='bezahlt').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);const open=(data||[]).filter(r=>r.status==='offen').reduce((s,r)=>s+(parseFloat(r.betrag)||0),0);window._rProj=proj||[];sC(`<div class="ph"><div><div class="pt">Rechnungen</div><div class="ps">${(data||[]).length} Rechnung(en)</div></div><button class="bp" onclick="mRech(window._rProj)">+ Erstellen</button></div><div class="sts" style="grid-template-columns:repeat(auto-fill,minmax(170px,1fr))"><div class="st g"><div class="si">✅</div><div class="sv">€${paid.toFixed(0)}</div><div class="sl">Bezahlt</div></div><div class="st o"><div class="si">⏳</div><div class="sv">€${open.toFixed(0)}</div><div class="sl">Offen</div></div></div><div class="tc"><table><thead><tr><th>Nr.</th><th>Datum</th><th>Kunde</th><th>Betrag</th><th>Status</th><th></th></tr></thead><tbody>${!(data&&data.length)?'<tr><td colspan="6"><div class="em" style="padding:30px"><div class="em-t">Keine Rechnungen</div></div></td></tr>':data.map(r=>`<tr onclick="mRechEdit('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||'offen'}','${r.projekt_id||''}')" style="cursor:pointer"><td style="font-family:monospace;font-size:11px">${r.rechnungsnummer||'-'}</td><td>${fmtDatum(r.datum)}</td><td>${r.kunde||'-'}</td><td><b>€${parseFloat(r.betrag||0).toFixed(2)}</b></td><td><span class="bd ${r.status==='bezahlt'?'bd-g':r.status==='offen'?'bd-o':'bd-r'}">${r.status||'offen'}</span></td><td style="white-space:nowrap"><button onclick="event.stopPropagation();exportRechPDF('${r.id}','${r.rechnungsnummer||''}','${r.datum||''}','${r.kunde||''}','${r.betrag||''}','${r.status||''}')" style="background:none;border:none;cursor:pointer;font-size:16px">📄</button><button onclick="event.stopPropagation();delRech('${r.id}')" style="background:none;border:none;cursor:pointer;color:var(--red);font-size:16px">🗑️</button></td></tr>`).join('')}</tbody></table></div>`);}catch(e){sC(`<div class="em"><div class="em-i">⚠️</div><div class="em-t">${e.message}</div></div>`);}}
function mRech(proj){const nr='RE-'+new Date().getFullYear()+'-'+String(Math.floor(Math.random()*9000)+1000);oM(`<div class="mt">Rechnung erstellen</div><div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(proj||[]).map(p=>`<option value="${p.id}">${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" placeholder="Müller GmbH"></div><div class="fg"><label>BETRAG (€) *</label><input id="f-b" type="number" step="0.01" placeholder="0.00"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen">Offen</option><option value="bezahlt">Bezahlt</option><option value="storniert">Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('')">Erstellen</button></div>`);}
function mRechEdit(id,nr,datum,kunde,betrag,status,pid){oM(`<div class="mt">Rechnung bearbeiten</div><div class="fr"><div class="fg"><label>RECHNUNGSNR.</label><input id="f-nr" value="${nr}"></div><div class="fg"><label>DATUM</label><input id="f-d" type="date" value="${datum||heute()}"></div></div><div class="fg"><label>PROJEKT</label><select id="f-p"><option value="">-</option>${(window._rProj||[]).map(p=>`<option value="${p.id}"${p.id===pid?' selected':''}>${p.name}</option>`).join('')}</select></div><div class="fg"><label>KUNDE *</label><input id="f-ku" value="${kunde}"></div><div class="fg"><label>BETRAG (€) *</label><input id="f-b" type="number" step="0.01" value="${betrag}"></div><div class="fg"><label>STATUS</label><select id="f-s"><option value="offen"${status==='offen'?' selected':''}>Offen</option><option value="bezahlt"${status==='bezahlt'?' selected':''}>Bezahlt</option><option value="storniert"${status==='storniert'?' selected':''}>Storniert</option></select></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveRech('${id}')">Speichern</button></div>`);}
async function saveRech(id){const ku=document.getElementById('f-ku').value.trim(),b=document.getElementById('f-b').value;if(!ku||!b){alert('Kunde und Betrag fehlen!');return;}const o={rechnungsnummer:document.getElementById('f-nr').value,projekt_id:document.getElementById('f-p').value||null,kunde:ku,datum:document.getElementById('f-d').value,betrag:parseFloat(b),status:document.getElementById('f-s').value};const{error}=id?await sb.from('rechnungen').update(o).eq('id',id):await sb.from('rechnungen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgRech();}
async function delRech(id){if(!confirm('Rechnung löschen?'))return;await sb.from('rechnungen').delete().eq('id',id);pgRech();}
function exportRechPDF(id,nr,datum,kunde,betrag,status){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[26,86,219];const grau=[100,116,139];const L=20,R=190,W=170;doc.setFillColor(...blau);doc.rect(0,0,210,45,'F');doc.setTextColor(255,255,255);doc.setFontSize(22);doc.setFont('helvetica','bold');doc.text('Rechnung',L,20);doc.setFontSize(10);doc.setFont('helvetica','normal');doc.text(settings.firma||'',L,30);doc.text(settings.adresse||'',L,37);doc.setTextColor(0,0,0);let y=55;doc.setFillColor(245,247,250);doc.roundedRect(L,y,W,30,2,2,'F');doc.setFontSize(9);doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.text('RECHNUNGSINFORMATIONEN',L+4,y+8);doc.setFont('helvetica','normal');doc.setTextColor(50,50,50);doc.text('Rechnungsnr.: '+nr,L+4,y+16);doc.text('Datum: '+fmtDatum(datum),L+4,y+23);doc.text('Status: '+status,L+100,y+16);y+=38;doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('RECHNUNGSEMPFAENGER',L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(30,30,30);doc.setFontSize(11);doc.text(kunde||'-',L,y);y+=20;doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('BETRAG',L,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(30,30,30);doc.setFontSize(18);doc.text('EUR '+parseFloat(betrag||0).toFixed(2),L,y);y+=12;const mwstSatz=settings.mwst||19;const netto=parseFloat(betrag||0)/(1+mwstSatz/100);const mwst=parseFloat(betrag||0)-netto;doc.setFontSize(9);doc.setFont('helvetica','normal');doc.setTextColor(...grau);doc.text('Netto: EUR '+netto.toFixed(2),L,y);y+=6;doc.text('MwSt ('+mwstSatz+'%): EUR '+mwst.toFixed(2),L,y);y+=20;if(settings.iban){doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('BANKVERBINDUNG',L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(30,30,30);doc.setFontSize(10);doc.text('IBAN: '+(settings.iban||'-'),L,y);y+=6;if(settings.bank)doc.text('Bank: '+settings.bank,L,y);y+=6;if(settings.zahlungsziel)doc.text('Zahlungsziel: '+settings.zahlungsziel+' Tage',L,y);}doc.setDrawColor(220,225,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO  |  '+new Date().toLocaleDateString('de-DE'),L,283);if(settings.ustid)doc.text('USt-ID: '+settings.ustid,R-40,283);doc.save('Rechnung_'+nr+'.pdf');}
async function mBt(pid){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');const schnell=['Maurerarbeiten','Fenster eingebaut','Elektroarbeiten','Sanitärarbeiten','Gerüst auf/abgebaut','Materiallieferung','Bauabnahme','Mangel festgestellt','Malerarbeiten','Metallbauarbeiten','Zimmerarbeiten','Dacharbeiten'];oM(`<div class="mt">Bautagesprotokoll</div><div style="background:var(--pl);border-radius:10px;padding:12px;margin-bottom:14px;font-size:13px"><div style="display:flex;align-items:center;gap:8px"><span>Datum:</span><input id="f-dat" type="date" value="${heute()}" style="border:none;background:transparent;font-weight:700;color:var(--pd);font-size:13px"></div></div><div class="fr"><div class="fg"><label>ZEIT VON</label><input id="f-zv" type="time" value="07:00"></div><div class="fg"><label>ZEIT BIS</label><input id="f-zb" type="time" value="16:00"></div></div><div class="fg"><label>GEWERK / FIRMA</label><input id="f-gw" placeholder="z.B. Maurer GmbH"></div><div class="fg"><label>ANWESENDE MITARBEITER</label><select id="f-mit"><option value="">- Wählen -</option>${mitOpts}</select></div><div class="fg"><label>TÄTIGKEITEN *</label><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px">${schnell.map(s=>`<button type="button" onclick="addText('f-desc','${s}')" style="padding:5px 10px;background:var(--pl);color:var(--pd);border:none;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit">${s}</button>`).join('')}</div><textarea id="f-desc" rows="4" placeholder="Beschreibung der Tätigkeiten..."></textarea></div><div class="fg"><label>VERWENDETES MATERIAL</label><textarea id="f-mat" rows="2" placeholder="z.B. 50 Sack Zement..."></textarea></div><div class="fg"><label>LIEFERUNGEN</label><input id="f-lief" placeholder="z.B. Holzlieferung Firma XY"></div><div class="fg"><label>MÄNGEL / BESONDERHEITEN</label><textarea id="f-maeng" rows="2" placeholder="z.B. Riss in Wand entdeckt..."></textarea></div><div class="fg"><label>FOTOS</label><div class="photo-up" onclick="document.getElementById('bt-fi').click()" style="padding:12px"><input type="file" id="bt-fi" accept="image/*" multiple style="display:none" onchange="previewBtFotos()"><div style="font-size:18px">📷</div><div style="font-size:12px;font-weight:700">Fotos hinzufügen</div></div><div id="bt-fp" class="photo-prev"></div></div><div class="fg"><label>UNTERSCHRIFT BAULEITER</label><canvas id="sig-bl" width="400" height="120" style="border:1.5px solid var(--border);border-radius:9px;background:#fff;touch-action:none;width:100%"></canvas><button type="button" onclick="clearSig('sig-bl')" style="margin-top:4px;padding:4px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;font-size:11px;cursor:pointer;font-family:inherit">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag" width="400" height="120" style="border:1.5px solid var(--border);border-radius:9px;background:#fff;touch-action:none;width:100%"></canvas><button type="button" onclick="clearSig('sig-ag')" style="margin-top:4px;padding:4px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;font-size:11px;cursor:pointer;font-family:inherit">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveBt('${pid}')">Speichern</button></div>`);initSig('sig-bl');initSig('sig-ag');}
function addText(id,txt){const el=document.getElementById(id);el.value+=(el.value?'\n':'')+txt;}
function initSig(id){const c=document.getElementById(id);if(!c)return;const ctx=c.getContext('2d');let drawing=false;const getPos=(e)=>{const r=c.getBoundingClientRect();const t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*(c.width/r.width),y:(t.clientY-r.top)*(c.height/r.height)};};c.addEventListener('mousedown',e=>{drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);});c.addEventListener('mousemove',e=>{if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#0f172a';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();});c.addEventListener('mouseup',()=>drawing=false);c.addEventListener('touchstart',e=>{e.preventDefault();drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y);},{passive:false});c.addEventListener('touchmove',e=>{e.preventDefault();if(!drawing)return;const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.strokeStyle='#0f172a';ctx.lineWidth=2;ctx.lineCap='round';ctx.stroke();},{passive:false});c.addEventListener('touchend',()=>drawing=false);}
function clearSig(id){const c=document.getElementById(id);c.getContext('2d').clearRect(0,0,c.width,c.height);}
function previewBtFotos(){const files=document.getElementById('bt-fi').files;const prev=document.getElementById('bt-fp');prev.innerHTML='';for(const f of files){const r=new FileReader();r.onload=e=>{const i=document.createElement('img');i.src=e.target.result;i.className='pt-img';i.onclick=()=>window.open(e.target.result,'_blank');i.style.cursor='pointer';prev.appendChild(i);};r.readAsDataURL(f);}}
async function saveBt(pid){const d=document.getElementById('f-desc').value.trim();if(!d){alert('Beschreibung fehlt!');return;}const sigBl=document.getElementById('sig-bl').toDataURL();const sigAg=document.getElementById('sig-ag').toDataURL();const dat=document.getElementById('f-dat');const mit=document.getElementById('f-mit');const{error}=await sb.from('bautagebuch').insert({projekt_id:pid,datum:dat?dat.value:heute(),beschreibung:d,gewerk:document.getElementById('f-gw').value,mitarbeiter:mit?mit.value:'',material_verwendet:document.getElementById('f-mat').value,lieferungen:document.getElementById('f-lief').value,maengel:document.getElementById('f-maeng').value,zeit_von:document.getElementById('f-zv').value,zeit_bis:document.getElementById('f-zb').value,unterschrift_bauleiter:sigBl,unterschrift_auftraggeber:sigAg,erstellt_von:me.email});if(error){alert('Fehler: '+error.message);return;}cM();pgProjDetail(pid);}
function mAbnahme(pid,pname,kunde){const mitOpts=_mitarbeiter.map(m=>`<option value="${m.name}">${m.name}</option>`).join('');oM(`<div class="mt">Abnahmeprotokoll</div><div style="background:var(--pl);border-radius:10px;padding:12px;margin-bottom:14px;font-size:13px"><div style="display:flex;justify-content:space-between"><span>Datum: ${new Date().toLocaleDateString('de-DE')}</span><span>Projekt: ${pname||'-'}</span></div></div><div class="fr"><div class="fg"><label>ORT</label><input id="f-ort" placeholder="z.B. Berlin"></div><div class="fg"><label>AUFTRAGGEBER</label><input id="f-ag" value="${kunde||''}" placeholder="Kunde / Vermieter"></div></div><div class="fg"><label>AUFTRAGNEHMER</label><input id="f-an" value="${settings.firma||''}" placeholder="Ihre Firma"></div><div class="fg"><label>BAULEITER</label><select id="f-bl"><option value="">- Wählen -</option>${mitOpts}</select></div><div class="fg"><label>ERLEDIGTE ARBEITEN</label><div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px">${['Maurerarbeiten','Elektroarbeiten','Sanitärarbeiten','Malerarbeiten','Bodenbelag','Fenster eingebaut','Türen eingebaut','Dacharbeiten','Gerüstarbeiten','Sonstige Arbeiten'].map(s=>`<button type="button" onclick="addText('f-arb','${s}')" style="padding:5px 10px;background:var(--pl);color:var(--pd);border:none;border-radius:20px;font-size:11px;font-weight:700;cursor:pointer;font-family:inherit">${s}</button>`).join('')}</div><textarea id="f-arb" rows="4" placeholder="Welche Arbeiten wurden durchgeführt?"></textarea></div><div class="fg"><label>MÄNGEL</label><textarea id="f-maeng" rows="3" placeholder="Keine Mängel / oder Mängel beschreiben..."></textarea></div><div class="fg"><label>MÄNGEL FRIST</label><input id="f-frist" type="date"></div><div class="fg"><label>BEMERKUNGEN</label><textarea id="f-bem" rows="2" placeholder="Sonstige Bemerkungen..."></textarea></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGNEHMER</label><canvas id="sig-an" width="400" height="120" style="border:1.5px solid var(--border);border-radius:9px;background:#fff;touch-action:none;width:100%"></canvas><button type="button" onclick="clearSig('sig-an')" style="margin-top:4px;padding:4px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;font-size:11px;cursor:pointer;font-family:inherit">Löschen</button></div><div class="fg"><label>UNTERSCHRIFT AUFTRAGGEBER</label><canvas id="sig-ag2" width="400" height="120" style="border:1.5px solid var(--border);border-radius:9px;background:#fff;touch-action:none;width:100%"></canvas><button type="button" onclick="clearSig('sig-ag2')" style="margin-top:4px;padding:4px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;font-size:11px;cursor:pointer;font-family:inherit">Löschen</button></div><div class="ma"><button class="bc" onclick="cM()">Abbrechen</button><button class="bs" onclick="saveAbnahme('${pid}')">Speichern & PDF</button></div>`);initSig('sig-an');initSig('sig-ag2');}
async function saveAbnahme(pid){const arb=document.getElementById('f-arb').value.trim();if(!arb){alert('Erledigte Arbeiten fehlen!');return;}const sigAn=document.getElementById('sig-an').toDataURL();const sigAg=document.getElementById('sig-ag2').toDataURL();const o={projekt_id:pid,datum:heute(),ort:document.getElementById('f-ort').value,auftragnehmer:document.getElementById('f-an').value,auftraggeber:document.getElementById('f-ag').value,arbeiten_erledigt:arb,maengel:document.getElementById('f-maeng').value,maengel_frist:document.getElementById('f-frist').value||null,bemerkungen:document.getElementById('f-bem').value,unterschrift_auftragnehmer:sigAn,unterschrift_auftraggeber:sigAg,erstellt_von:me.email};const{data,error}=await sb.from('abnahmen').insert(o).select().single();if(error){alert('Fehler: '+error.message);return;}cM();exportAbnahmePDF(o);}
function exportAbnahmePDF(a){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[26,86,219];const grau=[100,116,139];const L=20,R=190,W=170;doc.setFillColor(...blau);doc.rect(0,0,210,45,'F');doc.setTextColor(255,255,255);doc.setFontSize(22);doc.setFont('helvetica','bold');doc.text('Abnahmeprotokoll',L,20);doc.setFontSize(10);doc.setFont('helvetica','normal');doc.text(a.auftragnehmer||'',L,30);doc.text('Datum: '+new Date().toLocaleDateString('de-DE')+'  |  Ort: '+(a.ort||'-'),L,38);doc.setTextColor(0,0,0);let y=55;doc.setFillColor(245,247,250);doc.roundedRect(L,y,W,22,2,2,'F');doc.setFontSize(9);doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.text('PROJEKTINFORMATIONEN',L+4,y+8);doc.setFont('helvetica','normal');doc.setTextColor(50,50,50);doc.text('Auftragnehmer: '+(a.auftragnehmer||'-'),L+4,y+15);doc.text('Auftraggeber: '+(a.auftraggeber||'-'),L+95,y+15);y+=30;const sections=[{title:'ERLEDIGTE ARBEITEN',value:a.arbeiten_erledigt},{title:'MAENGEL',value:a.maengel||'Keine Maengel festgestellt'},{title:'BEMERKUNGEN',value:a.bemerkungen}];sections.forEach(s=>{if(!s.value)return;if(y>255){doc.addPage();y=20;}doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=5;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text(s.title,L,y);y+=5;doc.setFont('helvetica','normal');doc.setTextColor(30,30,30);doc.setFontSize(10);const lines=doc.splitTextToSize(s.value,W);lines.forEach(l=>{if(y>270){doc.addPage();y=20;}doc.text(l,L,y);y+=6;});y+=5;});if(a.maengel_frist){if(y>260){doc.addPage();y=20;}doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=5;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('FRIST ZUR MANGELBESEITIGUNG',L,y);y+=6;doc.setFont('helvetica','normal');doc.setTextColor(30,30,30);doc.setFontSize(10);doc.text(a.maengel_frist,L,y);y+=10;}if(y>190){doc.addPage();y=20;}doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('UNTERSCHRIFTEN',L,y);y+=8;const hasBl=a.unterschrift_auftragnehmer&&a.unterschrift_auftragnehmer.length>100;const hasAg=a.unterschrift_auftraggeber&&a.unterschrift_auftraggeber.length>100;if(hasBl){try{doc.addImage(a.unterschrift_auftragnehmer,'PNG',L,y,75,25);}catch(e){}}if(hasAg){try{doc.addImage(a.unterschrift_auftraggeber,'PNG',L+90,y,75,25);}catch(e){}}doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Auftragnehmer',L+20,y+30);doc.text('Auftraggeber',L+110,y+30);y+=38;doc.setDrawColor(220,225,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO  |  '+new Date().toLocaleDateString('de-DE'),L,283);doc.save('Abnahmeprotokoll_'+heute()+'.pdf');}
function pgEinst(){sC(`<div class="ph"><div><div class="pt">Einstellungen</div><div class="ps">Firma & App konfigurieren</div></div></div><div class="tc" style="margin-bottom:20px"><div class="th"><span class="th-t">Firmendaten</span></div><div style="padding:18px"><div class="fg"><label>FIRMENNAME</label><input id="s-firma" value="${settings.firma||''}" placeholder="Alem Facility GmbH"></div><div class="fg"><label>ADRESSE</label><input id="s-adr" value="${settings.adresse||''}" placeholder="Musterstr. 1, Berlin"></div><div class="fr"><div class="fg"><label>TELEFON</label><input id="s-tel" value="${settings.telefon||''}" placeholder="+49 ..."></div><div class="fg"><label>E-MAIL</label><input id="s-em" value="${settings.email||''}" placeholder="info@firma.de"></div></div></div></div><div class="tc" style="margin-bottom:20px"><div class="th"><span class="th-t">Rechnungseinstellungen</span></div><div style="padding:18px"><div class="fr"><div class="fg"><label>MWST (%)</label><input id="s-mwst" type="number" value="${settings.mwst||19}" placeholder="19"></div><div class="fg"><label>ZAHLUNGSZIEL (TAGE)</label><input id="s-ziel" type="number" value="${settings.zahlungsziel||14}" placeholder="14"></div></div><div class="fr"><div class="fg"><label>UST-ID</label><input id="s-ustid" value="${settings.ustid||''}" placeholder="DE123456789"></div><div class="fg"><label>STEUERNUMMER</label><input id="s-steuernr" value="${settings.steuernr||''}" placeholder="123/456/78901"></div></div><div class="fg"><label>IBAN</label><input id="s-iban" value="${settings.iban||''}" placeholder="DE89 3704 0044 0532 0130 00"></div><div class="fg"><label>BANK</label><input id="s-bank" value="${settings.bank||''}" placeholder="Deutsche Bank"></div></div></div><div class="tc" style="margin-bottom:20px"><div class="th"><span class="th-t">Konto</span></div><div style="padding:18px"><div class="fg"><label>E-MAIL</label><input value="${me?.email||''}" disabled style="background:#f0f4f8;color:var(--muted)"></div><div class="fg"><label>BENUTZER-ID</label><input value="${me?.id||''}" disabled style="background:#f0f4f8;color:var(--muted);font-size:11px;font-family:monospace"></div></div></div><button class="bp" style="width:100%;padding:14px;font-size:15px" onclick="saveSettings()">Einstellungen speichern</button>`);}
function exportBtPDF(bt,projektName,firmaName){const{jsPDF}=window.jspdf;const doc=new jsPDF();const blau=[26,86,219];const grau=[100,116,139];const L=20,R=190,W=170;doc.setFillColor(...blau);doc.rect(0,0,210,45,'F');doc.setTextColor(255,255,255);doc.setFontSize(22);doc.setFont('helvetica','bold');doc.text('Bautagesprotokoll',L,20);doc.setFontSize(10);doc.setFont('helvetica','normal');doc.text(firmaName||'',L,30);doc.text('Projekt: '+(projektName||''),L,38);doc.setTextColor(0,0,0);let y=55;doc.setFillColor(245,247,250);doc.roundedRect(L,y,W,26,2,2,'F');doc.setFontSize(8);doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.text('PROTOKOLL-INFORMATIONEN',L+4,y+7);doc.setFont('helvetica','normal');doc.setTextColor(50,50,50);doc.setFontSize(9);doc.text('Datum:',L+4,y+15);doc.text(bt.datum||'-',L+22,y+15);doc.text('Zeit:',L+70,y+15);doc.text((bt.zeit_von||'-')+' - '+(bt.zeit_bis||'-')+' Uhr',L+82,y+15);doc.text('Erstellt von:',L+4,y+22);doc.text(bt.erstellt_von||'-',L+28,y+22);y+=34;const sections=[{title:'GEWERK / FIRMA',value:bt.gewerk},{title:'ANWESENDE MITARBEITER',value:bt.mitarbeiter},{title:'DURCHGEFUEHRTE TAETIGKEITEN',value:bt.beschreibung},{title:'VERWENDETES MATERIAL',value:bt.material_verwendet},{title:'LIEFERUNGEN',value:bt.lieferungen},{title:'MAENGEL / BESONDERHEITEN',value:bt.maengel}];sections.forEach(s=>{if(!s.value)return;if(y>255){doc.addPage();y=20;}doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=5;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text(s.title,L,y);y+=5;doc.setFont('helvetica','normal');doc.setTextColor(30,30,30);doc.setFontSize(10);const lines=doc.splitTextToSize(s.value,W);lines.forEach(l=>{if(y>270){doc.addPage();y=20;}doc.text(l,L,y);y+=6;});y+=5;});const hasBl=bt.unterschrift_bauleiter&&bt.unterschrift_bauleiter.length>100;const hasAg=bt.unterschrift_auftraggeber&&bt.unterschrift_auftraggeber.length>100;if(hasBl||hasAg){if(y>200){doc.addPage();y=20;}doc.setDrawColor(220,225,235);doc.line(L,y,R,y);y+=6;doc.setFont('helvetica','bold');doc.setTextColor(...blau);doc.setFontSize(8);doc.text('UNTERSCHRIFTEN',L,y);y+=6;if(hasBl&&hasAg){try{doc.addImage(bt.unterschrift_bauleiter,'PNG',L,y,75,25);}catch(e){}try{doc.addImage(bt.unterschrift_auftraggeber,'PNG',L+90,y,75,25);}catch(e){}doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Bauleiter',L+30,y+30);doc.text('Auftraggeber',L+115,y+30);y+=36;}else if(hasBl){try{doc.addImage(bt.unterschrift_bauleiter,'PNG',L,y,75,25);}catch(e){}doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Bauleiter',L+30,y+30);y+=36;}else if(hasAg){try{doc.addImage(bt.unterschrift_auftraggeber,'PNG',L,y,75,25);}catch(e){}doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Auftraggeber',L+30,y+30);y+=36;}}doc.setDrawColor(220,225,235);doc.line(L,278,R,278);doc.setFontSize(7);doc.setTextColor(...grau);doc.text('Alem Facility PRO  |  '+new Date().toLocaleDateString('de-DE'),L,283);doc.save('Bautagesprotokoll_'+(bt.datum||heute())+'.pdf');}
async function loadAndExportBt(btId,projektName){const{data}=await sb.from('bautagebuch').select('*').eq('id',btId).single();if(data)exportBtPDF(data,projektName,settings.firma||'');}
sb.auth.getSession().then(({data:{session}})=>{if(session)sA(session.user);});
